import{_ as d,o as e,c as r,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"GNU Coreutils-псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Оптимизируйте рабочий процесс с псевдонимами GNU Coreutils для управления файлами, обработки текста и утилит контрольных сумм.","frontmatter":{"title":"GNU Coreutils-псевдонимы | Dotfiles","description":"Оптимизируйте рабочий процесс с псевдонимами GNU Coreutils для управления файлами, обработки текста и утилит контрольных сумм.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"GNU Coreutils-псевдонимы preview","canonical":"/ru/aliases/gnu/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"GNU Coreutils-псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"GNU Coreutils-псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/gnu/","sidebar":true,"meta":[{"name":"keywords","content":"gnu coreutils, shell aliases, linux utilities, file management, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"GNU Coreutils-псевдонимы - Dotfiles"},{"name":"twitter:description","content":"Оптимизируйте рабочий процесс с псевдонимами GNU Coreutils для управления файлами, обработки текста и утилит контрольных сумм."},{"name":"og:title","content":"GNU Coreutils-псевдонимы - Dotfiles"},{"name":"og:description","content":"Оптимизируйте рабочий процесс с псевдонимами GNU Coreutils для управления файлами, обработки текста и утилит контрольных сумм."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/gnu/index.md","filePath":"ru/aliases/gnu/index.md","lastUpdated":1773010926000}'),a={name:"ru/aliases/gnu/index.md"};function c(i,t,s,l,n,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="gnu-coreutils-псевдонимы" tabindex="-1">GNU Coreutils-псевдонимы <a class="header-anchor" href="#gnu-coreutils-псевдонимы" aria-label="Permalink to &quot;GNU Coreutils-псевдонимы&quot;">​</a></h1><p>Ярлыки для основных Unix-утилит для ускорения работы в командной строке.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Псевдонимы GNU Coreutils предоставляют сокращённые команды для стандартных Unix-утилит. Определённые в <code>gnu.aliases.sh</code> и автоматически загружаемые chezmoi, эти псевдонимы упрощают операции с файлами, обработку текста и задачи проверки данных.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="управление-фаилами" tabindex="-1">Управление файлами <a class="header-anchor" href="#управление-фаилами" aria-label="Permalink to &quot;Управление файлами&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>basename</code></td><td>Извлечь имя файла из пути</td></tr><tr><td><code>cp</code></td><td>Копировать файлы и директории</td></tr><tr><td><code>dirname</code></td><td>Извлечь путь директории</td></tr><tr><td><code>ln</code></td><td>Создать ссылки между файлами</td></tr><tr><td><code>loname</code></td><td>Показать имя ссылки</td></tr><tr><td><code>ls</code></td><td>Показать содержимое директории</td></tr><tr><td><code>mkdir</code></td><td>Создать директории</td></tr><tr><td><code>mkfifo</code></td><td>Создать именованные каналы (FIFO)</td></tr><tr><td><code>mknod</code></td><td>Создать блочные или символьные специальные файлы</td></tr><tr><td><code>mv</code></td><td>Переместить или переименовать файлы или директории</td></tr><tr><td><code>pathchk</code></td><td>Проверить валидность имени файла</td></tr><tr><td><code>pwd</code></td><td>Показать имя рабочей директории</td></tr><tr><td><code>readlink</code></td><td>Показать разрешённые символические ссылки</td></tr><tr><td><code>realpath</code></td><td>Показать разрешённый физический путь</td></tr><tr><td><code>rm</code></td><td>Удалить файлы или директории</td></tr><tr><td><code>rmdir</code></td><td>Удалить пустые директории</td></tr><tr><td><code>unlink</code></td><td>Удалить файлы или директории</td></tr></tbody></table><h3 id="обработка-текста" tabindex="-1">Обработка текста <a class="header-anchor" href="#обработка-текста" aria-label="Permalink to &quot;Обработка текста&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>awk</code></td><td>Язык сканирования и обработки шаблонов</td></tr><tr><td><code>cat</code></td><td>Объединить и отобразить файлы</td></tr><tr><td><code>csplit</code></td><td>Разбить файл на части по контексту</td></tr><tr><td><code>cut</code></td><td>Удалить секции из каждой строки файлов</td></tr><tr><td><code>diff</code></td><td>Сравнить файлы построчно</td></tr><tr><td><code>fold</code></td><td>Перенести каждую строку по указанной ширине</td></tr><tr><td><code>grep</code></td><td>Вывести строки, соответствующие шаблону</td></tr><tr><td><code>head</code></td><td>Вывести первую часть файлов</td></tr><tr><td><code>nl</code></td><td>Пронумеровать строки файлов</td></tr><tr><td><code>paste</code></td><td>Объединить строки файлов</td></tr><tr><td><code>patch</code></td><td>Применить diff-файл к оригиналу</td></tr><tr><td><code>ptx</code></td><td>Создать перестановочный индекс содержимого файла</td></tr><tr><td><code>sed</code></td><td>Потоковый редактор для фильтрации и преобразования текста</td></tr><tr><td><code>sort</code></td><td>Сортировать строки текстовых файлов</td></tr><tr><td><code>split</code></td><td>Разбить файл на части</td></tr><tr><td><code>tail</code></td><td>Вывести последнюю часть файлов</td></tr><tr><td><code>tr</code></td><td>Преобразовать или удалить символы</td></tr></tbody></table><h3 id="утилиты-контрольных-сумм" tabindex="-1">Утилиты контрольных сумм <a class="header-anchor" href="#утилиты-контрольных-сумм" aria-label="Permalink to &quot;Утилиты контрольных сумм&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>b2sum</code></td><td>Вычислить или проверить дайджесты BLAKE2</td></tr><tr><td><code>cksum</code></td><td>Вычислить контрольную сумму CRC и размер</td></tr><tr><td><code>sha1sum</code></td><td>Вычислить или проверить дайджесты SHA1</td></tr><tr><td><code>sha224sum</code></td><td>Вычислить или проверить дайджесты SHA224</td></tr><tr><td><code>sha256sum</code></td><td>Вычислить или проверить дайджесты SHA256</td></tr><tr><td><code>sha384sum</code></td><td>Вычислить или проверить дайджесты SHA384</td></tr><tr><td><code>sha512sum</code></td><td>Вычислить или проверить дайджесты SHA512</td></tr></tbody></table><h3 id="утилиты-кодирования" tabindex="-1">Утилиты кодирования <a class="header-anchor" href="#утилиты-кодирования" aria-label="Permalink to &quot;Утилиты кодирования&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Описание</th></tr></thead><tbody><tr><td><code>base32</code></td><td>Вывести или преобразовать данные base32</td></tr><tr><td><code>base64</code></td><td>Закодировать или декодировать данные base64</td></tr><tr><td><code>basenc</code></td><td>Закодировать или декодировать данные в различных форматах</td></tr></tbody></table>',14)])])}const b=d(a,[["render",c]]);export{m as __pageData,b as default};
